 20→    public function resumeFilter(array $input)
 21→    {
 22→        // 后面前端要通过名称进行筛选
 23→        $userId = AuthRecord::user()->user_id;
 24→        /**
 25→         * @sql CREATE INDEX round_screener_rpc_pro ON `hrmgt_new`.resume_filter (round_times, screener_id, rec_pro_id);
 26→         */
 27→
 28→        // 感觉得先取出所有符合条件的 token id
 29→
 30→        $time = now()->format('Y-m-d H:i:s');
 31→        $itemIdsQuery = AuthorityTokenMd::whereJsonContains('authorized_person', $userId)
 32→            ->whereRaw("expire_time >= TIMESTAMPDIFF(SECOND,created_at,'{$time}')")
 33→            ->where('type', 'resume')
 34→            ->select('item')
 35→            ->orderBy('id', 'desc');
 36→        // 查出来是一个 JSON array
 37→
 38→        // 先取出所有符合条件的流程，这一步筛选很快的
 39→        $rfRpcProIdSubQuery = ResumeFilterMd::where('round_times', 2)
 40→            ->where('screener_id', $userId)
 41→            ->select('rec_pro_id'); // 满足覆盖查询
 42→        // 然后在外部查询用 IN
 43→        $paginatedData = ResumeMd::with('GetResumeExperience')->with('FileStorePathInfo')
 44→            ->join('recruitment_procession as rp', 'rp.resume_id', 'resumes.id')
 45→            ->whereIn('resumes.id', $itemIdsQuery->pluck('item')->flatten())
 46→            // ->join('resume_filter as rf', 'rf.rec_pro_id', 'rp.id')
 47→            ->whereIn('rp.id', $rfRpcProIdSubQuery)
 48→            // ->leftJoin('jobs as b', 'b.job_id', 'rp.job_id')
 49→            // ->leftJoin('job_departments as d', 'd.department_id', 'b.department_id')
 50→            // ->selectRaw("rp.id as rec_pro_id ,resumes.*,resumes.id as resume_id,rp.status as rec_pro_status, rf.id as target_id, CONCAT(d.department_name,'-',b.job_name) as job_name, rf.filter_result")
 51→            ->selectRaw('rp.id as rec_pro_id ,resumes.*,resumes.id as resume_id,rp.status as rec_pro_status, rp.job_id as rec_job_id')
 52→            ->orderBy('resumes.id', 'DESC')
 53→            ->paginate(300)->toArray();
 54→
 55→        // , rf.id as target_id, CONCAT(d.department_name,'-',b.job_name) as job_name, rf.filter_result
 56→        // rf 需要 id 和 filter_result，再单独查一次，注意，不在上面查的原因是保证上面的查询可以分页，虽然现在没有分页，尬！
 57→        $rfs = ResumeFilterMd::where('round_times', 2)
 58→            ->where('screener_id', $userId)
 59→            ->select(['id', 'filter_result', 'rec_pro_id'])->get()->keyBy('rec_pro_id')->toArray();
 60→        $jobIds = collect($paginatedData['data'])->pluck('job_id')->toArray();
 61→        $jobInfo = JobsMd::alias('b')
 62→            ->whereIn('b.job_id', $jobIds)
 63→            ->leftJoin('job_departments as d', 'd.department_id', 'b.department_id')
 64→            ->selectRaw("b.job_id, CONCAT(d.department_name,'-',b.job_name) as job_name")->get()->keyBy('job_id')->toArray();
 65→
 66→        $recruitments = collect($paginatedData['data'])->map(function ($item) use ($rfs, $jobInfo) {
 67→            $normalized = $item;
 68→            $rpId = $item['rec_pro_id'] ?? -1;
 69→            $normalized['filter_result'] = Arr::get($rfs, $rpId, [])['filter_result'] ?? '';
 70→            $normalized['target_id'] = Arr::get($rfs, $rpId, [])['id'] ?? -1;
 71→            $normalized['job_name'] = Arr::get($jobInfo, $item['job_id'] ?? -1, [])['job_name'] ?? '';
 72→            return $normalized;
 73→        })->toArray();
 74→
 75→        // 不再使用
 76→        /*
 77→        $recruitments = ResumeMd::with('GetResumeExperience')->with('FileStorePathInfo')
 78→            ->join('recruitment_procession as rp', 'rp.resume_id', 'resumes.id')
 79→            ->join('resume_filter as rf', 'rf.rec_pro_id', 'rp.id')
 80→            ->leftJoin('jobs as b', 'b.job_id', 'rp.job_id')
 81→            ->leftJoin('job_departments as d', 'd.department_id', 'b.department_id')
 82→            ->where('rf.round_times', 2)
 83→            ->where('rf.screener_id', $userId)
 84→            ->selectRaw("rp.id as rec_pro_id ,resumes.*,resumes.id as resume_id,rp.status as rec_pro_status, rf.id as target_id, CONCAT(d.department_name,'-',b.job_name) as job_name, rf.filter_result")
 85→            ->get()->toArray();
 86→        */
 87→        [$recruitments, $tokens] = $this->filterToken($recruitments);
 88→
 89→        return [
 90→            'resume_filter' => $recruitments, 'decrypt_config' => ['tokens' => $tokens],
 91→            'current_page' => $paginatedData['current_page'],
 92→            'per_page' => $paginatedData['per_page'],
 93→            'total' => $paginatedData['total'],
 94→        ];
 95→    }
