167→    public function updateInterviewResult(int $id, array $updateInfo): void
168→    {
169→        $ir = InterviewRecordsMd::find($id);
170→        if (!app(RecruitmentProcessService::class)->judgeChangeLogic($ir->rec_pro_id, RecruitmentProcessionMd::REC_STATUS['面试'])) {
171→            throw new InternalException(__('my_api.not_in_interview_status'), 801);
172→        }
173→        if ($ir->interview_result !== '') {
174→            throw new InternalException(__('my_api.interview_round_has_result'), 802);
175→        }
176→        $ir->update($updateInfo);
177→    }
