179→    public function offerApproval($day, $offer_ids = null)
180→    {
181→        $userId = AuthRecord::user()->user_id;
182→        $query = ResumeMd::with('GetResumeExperience')->with('FileStorePathInfo')
183→            ->join('recruitment_procession as rp', 'rp.resume_id', 'resumes.id')
184→            ->join('offer_approval as oa', 'oa.rec_pro_id', 'rp.id')
185→            ->leftjoin('jobs as b', 'b.job_id', 'oa.job_id')
186→            ->leftjoin('job_departments as d', 'd.department_id', 'b.department_id')
187→            ->where('oa.approver_id', $userId)
188→            ->where('oa.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-{$day} day")))
189→            ->selectRaw("resumes.*,resumes.id as resume_id,rp.status as rec_pro_status, rp.id as rec_pro_id, oa.id as target_id, CONCAT(d.department_name,'-',b.job_name) as job_name,
190→                oa.approval_status, oa.probation_time, oa.salary, oa.probation_salary, oa.operator_id, oa.intern_salary, oa.remark as oa_remark, oa.approver_id, oa.reject_reason, oa.created_at");
191→
192→        if (is_array($offer_ids)) {
193→            $query->whereIn('oa.id', $offer_ids);
194→        }
195→        $offers = $query->get()->toArray();
196→
197→        if (empty($offers)) {
198→            return ['offers' => [], 'decrypt_config' => ['tokens' => []]];
199→        }
200→
201→        $resumeIds = array_column($offers, 'resume_id');
202→        $recProIds = array_column($offers, 'rec_pro_id');
203→
204→        // 最近一次「offer创建」时间
205→        $offerMap = ResumeRecruitmentCacheMd::whereIn('resume_id', $resumeIds)
206→            ->where('type', 'create_offer')
207→            ->selectRaw('max(created_at) as created_at, resume_id')
208→            ->groupBy('resume_id')
209→            ->get()
210→            ->keyBy('resume_id')
211→            ->toArray();
212→
213→        // 最近一次入职时间
214→        $waitingEntryMap = WaitingEntryMd::whereIn('rec_pro_id', $recProIds)
215→            ->selectRaw('max(entry_time) as entry_time, rec_pro_id')
216→            ->groupBy('rec_pro_id')
217→            ->get()
218→            ->keyBy('rec_pro_id')
219→            ->toArray();
220→
221→        foreach ($offers as &$offer) {
222→            $resumeId = $offer['resume_id'] ?? 0;
223→            $recProId = $offer['rec_pro_id'] ?? 0;
224→            $offer['offer_create_time'] = Arr::get($offerMap, "{$resumeId}.created_at", '');
225→            $offer['entry_time'] = Arr::get($waitingEntryMap, "{$recProId}.entry_time", '');
226→        }
227→        unset($offer);
228→
229→        [$offers, $tokens] = $this->filterToken($offers);
230→
231→        return ['offers' => $offers, 'decrypt_config' => ['tokens' => $tokens]];
232→    }
