234→    public function entryArrangement($day)
235→    {
236→        $userId = AuthRecord::user()->user_id;
237→        $recs = ResumeMd::alias('re')->with('GetResumeExperience')->with('FileStorePathInfo')
238→            ->join('recruitment_procession as rp', 're.id', '=', 'rp.resume_id')
239→            ->leftJoin('interview_records as ir', 'rp.id', '=', 'ir.rec_pro_id')
240→            ->join('offer_approval as oa', 'oa.rec_pro_id', '=', 'rp.id')
241→            ->join('waiting_entry as we', 'rp.id', '=', 'we.rec_pro_id')
242→            ->leftjoin('jobs as b', 'b.job_id', 'oa.job_id')
243→            ->leftjoin('job_departments as d', 'd.department_id', 'b.department_id')
244→            ->where(function ($query) use ($userId, $day) {
245→                $query->where('oa.approver_id', $userId)
246→                    ->where('oa.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-{$day} day")))
247→                    ->where('rp.status', 'wait_entry')
248→                    ->where('oa.approval_status', 'accept_offer');
249→            })
250→            ->orWhere(function ($query) use ($userId, $day) {
251→                $query->where('ir.interviewer_id', '=', $userId)
252→                    ->where('ir.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-{$day} day")))
253→                    ->where('rp.status', 'wait_entry')
254→                    ->where('oa.approval_status', 'accept_offer');
255→            })
256→            ->orWhere(function ($query) use ($userId, $day) {
257→                $query->where('we.supervisor_id', '=', $userId)
258→                    ->where('we.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-{$day} day")))
259→                    ->where('rp.status', 'wait_entry')
260→                    ->where('oa.approval_status', 'accept_offer');
261→            })
262→            ->selectRaw("distinct re.*, re.id as resume_id, rp.id as rec_pro_id , CONCAT(d.department_name,'-',b.job_name) as job_name, if (oa.approver_id = '{$userId}' or we.supervisor_id  = '{$userId}' , 1, 0) as is_oa")
263→            ->orderBy('we.entry_time')
264→            ->get()->toArray();
265→
266→        [$recs, $tokens] = $this->filterToken($recs);
267→
268→        $subquery = WaitingEntryMd::whereIn('rec_pro_id', array_column($recs, 'rec_pro_id'))->groupBy('rec_pro_id')->selectRaw('rec_pro_id,MAX(id) AS max_id');
269→
270→        $waiting_entry = WaitingEntryMd::alias('we')
271→            ->joinSub($subquery, 'tmp', 'we.id', '=', 'tmp.max_id')
272→            ->leftjoin('jobs as b', 'b.job_id', '=', 'we.job_id')
273→            ->selectRaw('we.*, b.job_name as entry_job_name')->get()->toArray();
274→
275→        $waiting_entry = array_column($waiting_entry, null, 'rec_pro_id');
276→        $users = userInfo();
277→        foreach ($recs as &$recruitment) {
278→            $recruitment['waiting_entry'] = $waiting_entry[$recruitment['rec_pro_id']] ?? [];
279→            if (!$recruitment['is_oa']) {
280→                $recruitment['waiting_entry'] = Arr::only($recruitment['waiting_entry'], ['rec_pro_id', 'entry_time', 'entry_job_name', 'follow_up_hr_id', 'work_schedule']);
281→                $recruitment = Arr::except($recruitment, ['nickname']);
282→            } else {
283→                $recruitment['waiting_entry'] = Arr::only($recruitment['waiting_entry'], ['rec_pro_id', 'entry_time', 'entry_job_name', 'supervisor_id', 'mentor', 'seat', 'remark', 'follow_up_hr_id', 'work_schedule', 'is_overseas_student', 'is_intern', 'is_part_time', 'work_place', 'work_type', 'is_foreigner', 'is_hmt', 'is_tripartite_agreement_signed', 'is_social_recruitment']);
284→                $recruitment['waiting_entry']['supervisor'] = Arr::get($users, "{$recruitment['waiting_entry']['supervisor_id']}.nickname", '');
285→            }
286→            $recruitment['waiting_entry']['follow_up_hr'] = Arr::get($users, "{$recruitment['waiting_entry']['follow_up_hr_id']}.nickname", '');
287→        }
288→        return ['entry_arrangement' => $recs, 'decrypt_config' => ['tokens' => $tokens]];
289→    }
