291→    public function addToken($resumes, $resume_id)
292→    {
293→        return array_values(array_filter(array_map(function ($re) use ($resume_id) {
294→            $re['token'] = getAuthorityToken(AuthRecord::user()->user_id, $resume_id ?? $re['resume_id']);
295→            return $re; // 更新工作年份及年龄
296→        }, $resumes), function ($re) {
297→            return $re['token'] !== null;
298→        }));
299→    }
300→
301→    protected function filterToken($recruitments)
302→    {
303→        $tokens = [];
304→        $newRecs = array_values(array_filter($recruitments, function ($ir) use (&$tokens) {
305→            $token = getAuthorityToken(AuthRecord::user()->user_id, $ir['resume_id']);
306→            $tokens[] = $token;
307→            return $token !== null;
308→        }));
309→
310→        return [$newRecs, array_values(array_unique(array_filter($tokens)))];
311→    }
312→
313→    protected function updateResumeInfo($recruitment)
314→    {
315→        $work_seconds = 0;
316→        foreach ($recruitment['get_resume_experience'] as $value) {
317→            if ($value['type'] == 'work') {
318→                if (empty($value['end_time'])) { // 为空表示至今
319→                    $value['end_time'] = date('Y-m');
320→                }
321→                $work_seconds += strtotime(str_replace('.', '-', $value['end_time'] ?? '')) - strtotime(str_replace('.', '-', $value['start_time'] ?? '')); // 添加工作年月
322→            }
323→        }
324→        $recruitment['work_month'] = $this->getYearBySecond((int)$work_seconds);
325→
326→        return $recruitment;
327→    }
328→
329→    /**
330→     * 根据描述算出年份，向下取整.
331→     *
332→     * @param int $seconds
333→     * @return string
334→     */
335→    protected function getYearBySecond(int $seconds)
336→    {
337→        $result = __('my_api.none');
338→        if ($seconds >= 86400 * 365) {
339→            $year = floor($seconds / (86400 * 365));
340→            $result = $year.__('my_api.year');
341→        }
342→        return $result;
343→    }
344→
345→    protected function filterAddToken($recruitments)
346→    {
347→        $tokens = [];
348→        $newRecs = array_values(array_filter(array_map(function ($re) {
349→            $re['token'] = getAuthorityToken(AuthRecord::user()->user_id, $re['resume_id']);
350→            return $re;
351→        }, $recruitments), function ($re) use (&$tokens) {
352→            $tokens[] = $re['token'];
353→            return $re['token'] !== null;
354→        }));
355→        return [$newRecs, array_values(array_unique(array_filter($tokens)))];
356→    }
357→}
