 37→     * 根据结果是否进入面试.
 38→     *
 39→     * @param Request $request
 40→     * @return JsonResponse
 41→     */
 42→    public function toInterview(Request $request)
 43→    {
 44→        $rec_pro_id = $request->input('id'); // 获取招聘流程id
 45→        $input = Arr::only($request->all(), [
 46→            'id', 'result', 'round_times', 'archive_reason', 'specific_reason', 'is_send_rejection_letter',
 47→        ]) + ['archive_reason' => '', 'specific_reason' => ''];
 48→        $input['rec_pro_id'] = $rec_pro_id;
 49→
 50→        // 查看当前状态, 看是否复筛或者笔试状态中
 51→        $rec = RecruitmentProcessionMd::find($rec_pro_id);
 52→        if (!in_array($rec->status, ['re_scr', 'written_exam'])) {
 53→            return $this->responseJsonFail(__('my_api.recruitment_not_second_screening'), 801);
 54→        }
 55→        app(RecruitmentProcessService::class)->toInterview($input, $rec->status);
 56→
 57→        return $this->responseJsonSuccess([]);
 58→    }
