import _ from 'lodash'
import moment from 'moment'

import axios2 from '@/ajax/axios2'
import { genderTranslator, highestEdu } from '@/apis/StaffRequestApis/staffDataTranslator'
import { ajaxUrl } from '@/appConstant'
import { getInterviewResultMap, uploadDict } from '@/common/MDictionary'
import i18n from '@/i18n'

import { CommMap, getCommMapAPI } from './getCommMapAPI'
import { getOfferStatusDefault } from '@apis/constant'

// 面试官 简历筛选数据查询
export const interviewerResumeFilterAPI = () => {
    const decrypt_config = {
        obj: 'resume_filter.*',
        decrypt_columns: [
            'birth_year',
            'filing_reason',
            'gender',
            'username',
            'nickname',
            'mobile_num',
            'email',
            ...['probation_time', 'salary', 'probation_salary', 'intern_salary', 'offer_pdf', 'reject_reason', 'remark'].map(
                el => 'offer_approval.' + el,
            ),
            ...[
                'mentor',
                'seat',
                'signed_bonus',
                'insurance_account',
                'remark',
                'work_type',
                'work_place',
                'work_schedule',
                'is_green_code',
                'is_overseas_student',
                'is_send_entry_notice_mail',
                'is_settle_down',
                'is_shanghainese',
                'is_social_fund_in_sh',
                'is_social_recruitment',
                'is_tripartite_agreement_signed',
                'is_intern',
                'is_part_time',
                'is_foreigner',
                'is_hmt',
            ].map(el => 'waiting_entry.' + el),
            ...['description', 'details', 'name'].map(el => 'get_resume_experience.*.' + el),
        ],
    }
    return new Promise((resolve, reject) => {
        axios2(`${ajaxUrl.SERVER_API_URL}interviewer-workbench/resume-filter`, 'post', { decrypt_config })
            .then((rsp: any) => {
                // 待反馈列表
                const waitTableData = []
                // 已反馈列表
                const doneTableData = []
                if (rsp.resume_filter && rsp.resume_filter.length) {
                    rsp.resume_filter.forEach(a => {
                        // 计算 教育经历 工作经历
                        a.edu_exp = []
                        a.work_exp = []
                        _.sortBy(a.get_resume_experience, o => o.start_time)
                            .reverse()
                            .forEach(a2 => {
                                let startTime = moment(a2.start_time).format('YYYY.MM')
                                let endTime = moment(a2.end_time).format('YYYY.MM')
                                // 开始时间，结束时间校验
                                startTime === 'Invalid date' && (startTime = `${i18n.t('unknown')}`)
                                endTime === 'Invalid date' && (endTime = `${i18n.t('untilNow')}`)
                                if (a2.type === 'education') {
                                    a2.edu_name = highestEdu([a2.name]) // 学历翻译
                                    const [school, major] = a2.description.split('|')
                                    a2.edu_exp_descrip = [
                                        school || `${i18n.t('unknown')}`,
                                        major || `${i18n.t('unknown')}`,
                                        a2.edu_name,
                                        startTime,
                                        endTime,
                                    ]
                                    a.edu_exp.push(a2)
                                } else if (a2.type === 'work') {
                                    a2.work_exp_descrip = [a2.description, a2.name, startTime, endTime]
                                    a.work_exp.push(a2)
                                }
                            })
                        a.show_edu_exp = _.slice(a.edu_exp, 0, 2)
                        a.show_work_exp = _.slice(a.work_exp, 0, 2)
                        // 简历创建时间格式修改
                        a.created_at = moment(a.created_at).format('YYYY-MM-DD')
                        // 基本资料数据拼接
                        a.base_info = [
                            genderTranslator(a.gender),
                            _.defaultTo(moment().diff(moment(a.birth_year), 'years'), `${i18n.t('unknown')}`),
                            highestEdu(a.edu_exp.map(a2 => a2.name)),
                        ]
                            .filter(a2 => a2)
                            .join(' · ')
                        if (a.filter_result) {
                            doneTableData.push(a)
                        } else if (!a.rec_pro_status || a.rec_pro_status !== 'archive') {
                            waitTableData.push(a)
                        }
                    })
                }
                resolve({ waitTableData, doneTableData })
            })
            .catch(err => {
                console.error('interviewerResumeFilterAPI err', err)
                reject(err)
            })
    })
}

// 面试官工作台 面试日程所有数据查询
export const interviewerInterviewSAPI = (
    param: Partial<{ nickname: string[], jobName: string, interview_result: string, day:number, rpid: any }>,
    page,
    perPage,
    type,
): Promise<{
    data: any[]
    total: number
    // doneTable: any[]
    // waitTable: any[]
}> =>
    new Promise((resolve, reject) => {
        Promise.all([
            getCommMapAPI([CommMap.JobMap, CommMap.HRMap]),
            axios2(`${ajaxUrl.SERVER_API_URL}interviewer-workbench/interview-schedule`, 'post', {
                decrypt_config: {
                    obj: 'interview_records.*',
                    decrypt_columns: [
                        'username',
                        'nickname',
                        'remark',
                        'specific_reason',
                        'interview_evaluation',
                        'exam_list.*.evaluation',
                        'exam_list.*.file_store_path_info.*.file_store_path',
                    ],
                },
                include_columns: ['day','interview_result'],
                interview_result: param.interview_result,
                day: param.day,
                ...(param.rpid ? { rpid: param.rpid } : {}),
            }),
        ])
            .then(([map, r]) => {
                const ascdesc = type === 'bi_wait' ? 'asc' : 'desc'
                let arr = r.interview_records || []
                // 按照面试时间进行排序
                arr = _.orderBy(arr, o => o.interview_time, [ascdesc])
                // 分组，分为待评价、历史评价两组数据
                const interviewMap = getInterviewResultMap()
                const data = _.orderBy(
                    r.interview_records.filter(o => {
                        let typeMatch = false
                        let nickNameMatch = true
                        let jobNameMatch = true
                        let jobStatusMatch = true
                        if (type === 'bi_wait' && !o.interview_result && o.rec_pro_status === 'interview') {
                            typeMatch = true
                        }
                        if (type === 'bi_history' && (o.interview_result || o.rec_pro_status !== 'interview')) {
                            typeMatch = true
                        }
                        if (param?.nickname?.length) {
                            nickNameMatch = param.nickname.includes(o.username)
                        }
                        if (param?.jobName && o.job_name) {
                            jobNameMatch = o.job_name.includes(param.jobName)
                        }
                        if (param?.interview_result) {
                            const offerStatus = o.approval_status
                            const stage = o.rec_pro_status
                            const rejectReason = o.rejectReason
                            const createOfferTime = o.createOfferTime
                            const offerStatusDefault = getOfferStatusDefault(offerStatus, stage, rejectReason, createOfferTime)
                            jobStatusMatch = offerStatusDefault.includes(param.interview_result)
                        }
                        return typeMatch && nickNameMatch && jobNameMatch && jobStatusMatch
                    }),
                    ['interview_time'],
                    [ascdesc],
                ).map(o => ({
                    ...o,
                    iResult: {
                        label: interviewMap.getByValue(o.interview_result)?.label || '',
                        btnName: interviewMap.getByValue(o.interview_result) ? `${i18n.t('t0636')}` : `${i18n.t('t0637')}`,
                        color: interviewMap.getByValue(o.interview_result)?.color || '', // 评价字体颜色
                    },
                    bindFile: uploadDict.getFileFromUniqueName(map[CommMap.JobMap].getById(o.rp_job_id)?.fileUniqueName),
                    bindFilePath: uploadDict.getDownLoadUrl(map[CommMap.JobMap].getById(o.rp_job_id)?.fileUniqueName, 'job', 'comm'),
                    HRNickname: map[CommMap.HRMap].getById(o.inputer_user_id)?.label || '-',
                }))
                resolve({
                    data: _.slice(data, page * perPage - perPage, page * perPage),
                    total: data.length,
                })
            })
            .catch(e => {
                console.error('interviewerInterviewSAPI err', e)
                reject(e)
            })
    })

export interface InterviewResult {
    id: number
    resume_id: number
    interview_result: string
    interview_evaluation: string
}
// 面试官工作台 面试评价编辑
export const interviewerInterviewResultAPI = (
    type: 'add' | 'update',
    param,
    interviewRecId: number,
    resumeId: number,
    result: string,
    rate: string,
    evaluation: string,
) => {
    param.encrypt_config = {
        res_type: 'resume',
        obj: '$this',
        non_encrypt_columns: ['sys_lang', 'version_info', 'id', 'interview_result'],
    }
    let url = 'interviewer-workbench/interview-result'
    type === 'update' && (url = 'interviewer-workbench/update-interview-evaluation')
    return new Promise((resolve, reject) => {
        axios2(
            type === 'add'
                ? `${ajaxUrl.WEB_API_URL}interviewer-workbench/interview-result`
                : `${ajaxUrl.WEB_API_URL}interviewer-workbench/update-interview-evaluation`,
            'post',
            {
                encrypt_config: {
                    res_type: 'resume',
                    obj: '$this',
                    non_encrypt_columns: ['sys_lang', 'version_info', 'id', 'interview_result'],
                },
                id: interviewRecId,
                resume_id: resumeId,
                interview_result: result,
                interview_evaluation: `${rate}\n${evaluation}`,
            },
        )
            .then(r => {
                resolve(r)
            })
            .catch(e => {
                console.error('interviewerInterviewResultAPI', e)
                reject(e?.error_msg || i18n.t('e1'))
            })
    })
}

