+<?php
+
+namespace App\Service;
+
+use App\Models\ResumeMd;
+use App\Support\Common\AuthRecord;
+use App\Models\InterviewRecordsMd;
+use App\Models\RecruitmentProcessionMd;
+use Illuminate\Support\Arr;
+use App\Models\WaitingEntryMd;
+
+class InterviewerWorkbenchService
+{
+    public function resumeFilter($day)
+    {
+        $screener_name_hash = md5(AuthRecord::user()->nickname);
+        $recruitments = ResumeMd::with('GetResumeExperience')->with('FileStorePathInfo')
+            ->join('recruitment_procession as rp', 'rp.resume_id', 'resumes.id')
+            ->join('resume_filter as rf', 'rf.rec_pro_id', 'rp.id')
+            ->join('jobs as b', 'b.job_id', 'rp.job_id')
+            ->join('job_departments as d', 'd.department_id', 'b.department_id')
+            ->where('rf.round_times', 2)
+            ->where('rf.screener_name_hash', $screener_name_hash)
+            ->where('rf.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-$day day")))
+            ->selectRaw("rp.id as rec_pro_id ,resumes.*,resumes.id as resume_id, rf.id as target_id, CONCAT(d.department_name,'-',b.job_name) as job_name, rf.filter_result")
+            ->get()->toArray();
+
+        $recruitments = $this->filterToken($recruitments);
+
+        return ['resume_filter' => $recruitments];
+    }
+
+    public function interviewSchedule($day): array
+    {
+        $interviewer_hash = md5(AuthRecord::user()->nickname);
+        $interviewRecords = ResumeMd::alias('re')->with('GetResumeExperience')->with('FileStorePathInfo')
+            ->join('recruitment_procession as rp', 're.id', '=', 'rp.resume_id')
+            ->join('interview_records as ir', 'ir.rec_pro_id', 'rp.id')
+            ->join('jobs as b', 'b.job_id', 'rp.job_id')
+            ->join('job_departments as d', 'd.department_id', 'b.department_id')
+            ->where('ir.interviewer_name_hash', '=', $interviewer_hash)
+            ->where('ir.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-$day day")))
+            ->selectRaw("re.*,re.id as resume_id,ir.*, CONCAT(d.department_name,'-',b.job_name) as job_name , rp.filled_reason as filled_reason , ir.operator_name as HR_name, rp.job_id as rp_job_id")
+            ->get()->toArray();
+
+        $interviewRecords = $this->filterToken($interviewRecords);
+
+        return ['interview_records' => $interviewRecords];
+    }
+
+    public function updateInterviewResult(int $id, array $updateInfo): void
+    {
+        $ir = InterviewRecordsMd::find($id);
+        if (!app(RecruitmentProcessService::class)->judgeChangeLogic($ir->rec_pro_id, RecruitmentProcessionMd::REC_STATUS['面试'])) {
+            throw new \InternalException('该招聘流程未在面试状态', 801);
+        }
+        if ($ir->interview_result !== '') {
+            throw new \InternalException('该面试轮次已有结果', 802);
+        }
+        $ir->update($updateInfo);
+    }
+
+    public function offerApproval($day, $offer_ids = null)
+    {
+        $approver_hash = md5(AuthRecord::user()->nickname);
+        $query = ResumeMd::with('GetResumeExperience')->with('FileStorePathInfo')
+            ->join('recruitment_procession as rp', 'rp.resume_id', 'resumes.id')
+            ->join('offer_approval as oa', 'oa.rec_pro_id', 'rp.id')
+            ->leftjoin('jobs as b', 'b.job_id', 'oa.job_id')
+            ->leftjoin('job_departments as d', 'd.department_id', 'b.department_id')
+            ->where('oa.approver_name_hash', $approver_hash)
+            ->where('oa.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-$day day")))
+            ->selectRaw("resumes.*,resumes.id as resume_id, rp.id as rec_id, oa.id as target_id, CONCAT(d.department_name,'-',b.job_name) as job_name,
+                oa.approval_status, oa.probation_time, oa.salary, oa.probation_salary, oa.intern_salary, oa.remark as oa_remark, oa.approver_name");
+
+        if (is_array($offer_ids)) {
+            $query->whereIn('oa.id', $offer_ids);
+        }
+        $offers = $query->get()->toArray();
+
+        $offers = $this->filterToken($offers);
+        return ['offers' => $offers];
+    }
+
+    public function entryArrangement($day)
+    {
+        $name_hash = md5(AuthRecord::user()->nickname);
+        $recs = ResumeMd::alias('re')->with('GetResumeExperience')->with('FileStorePathInfo')
+            ->join('recruitment_procession as rp', 're.id', '=', 'rp.resume_id')
+            ->join('interview_records as ir', 'rp.id', '=', 'ir.rec_pro_id')
+            ->join('offer_approval as oa', 'oa.rec_pro_id', '=', 'rp.id')
+            ->leftjoin('jobs as b', 'b.job_id', 'oa.job_id')
+            ->leftjoin('job_departments as d', 'd.department_id', 'b.department_id')
+            ->where(function ($query) use ($name_hash, $day) {
+                $query->where('oa.approver_name_hash', $name_hash)
+                    ->where('oa.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-$day day")))
+                    ->where('rp.status', 'wait_entry');
+            })
+            ->orWhere(function ($query) use ($name_hash, $day) {
+                $query->where('ir.interviewer_name_hash', '=', $name_hash)
+                    ->where('ir.updated_at', '>=', date('Y-m-d H:i:s', strtotime("-$day day")))
+                    ->where('rp.status', 'wait_entry');
+            })
+            ->selectRaw("re.*, re.id as resume_id, rp.id as rec_id , CONCAT(d.department_name,'-',b.job_name) as job_name, if (oa.approver_name_hash = '$name_hash' , 1, 0) as is_oa")
+            ->get()->toArray();
+
+        $recs = $this->filterToken($recs);
+
+        $subquery = WaitingEntryMd::whereIn('rec_pro_id', array_column($recs, 'rec_id'))->groupBy('rec_pro_id')->selectRaw("rec_pro_id,MAX(id) AS max_id");
+
+        $waiting_entry = WaitingEntryMd::alias('we')
+            ->joinSub($subquery, 'tmp', 'we.id', '=', 'tmp.max_id')
+            ->leftjoin('jobs as b', 'b.job_id', '=', 'we.job_id')
+            ->selectRaw('we.*, b.job_name as entry_job_name')->get()->toArray();
+
+        $waiting_entry = array_column($waiting_entry, null, 'rec_pro_id');
+
+        foreach ($recs as &$recruitment) {
+            $recruitment['waiting_entry'] = $waiting_entry[$recruitment['rec_id']] ?? [];
+            if (!$recruitment['is_oa']) {
+                $recruitment['waiting_entry'] = Arr::only($recruitment['waiting_entry'], ['rec_pro_id', 'entry_time', 'entry_job_name']);
+            }
+        }
+        return ['entry_arrangement' => $recs];
+    }
+
+    protected function filterToken($recruitments)
+    {
+        $recruitments = array_values(array_filter(array_map(function ($ir) {
+            $key = my_json_encode([
+                'authorized_person' => AuthRecord::user()->user_id,
+                'operator' => 'decrypt',
+                'item' => $ir['resume_id'],
+            ]);
+            $ir['token'] = redis()->get($key);
+            $ir = $this->updateResumeInfo($ir); // 更新工作年份及年龄
+            return $ir;
+        }, $recruitments), function ($ir) {
+            return $ir['token'] !== null;
+        }));
+        return $recruitments;
+    }
+
+    protected function updateResumeInfo($recruitment)
+    {
+        $work_seconds = 0;
+        foreach ($recruitment['get_resume_experience'] as $value) {
+            if ($value['type'] == 'work') {
+                if (empty($value['end_time'])) { //为空表示至今
+                    $value['end_time'] = date('Y-m');
+                }
+                $work_seconds += strtotime($value['end_time']) - strtotime($value['start_time']); //添加工作年月
+            }
+        }
+        $recruitment['work_month'] = $this->getYearBySecond((int) $work_seconds);
+
+        if (empty($recruitment['birth_year'])) {
+            $recruitment['age'] = '';
+        } else {
+            try {
+                $recruitment['age'] = date('Y') - substr($recruitment['birth_year'], 0, 4); //添加年龄
+                if (date('m') < (substr($recruitment['birth_year'], 5, 2) ?? '01')) {
+                    $recruitment['age']--;
+                }
+            } catch (\Exception $e) {
+                return $recruitment;
+            }
+        }
+        return $recruitment;
+    }
+
+    /**
+     * 根据描述算出年份，向下取整
+     *
+     * @param integer $second
+     * @return void
+     */
+    protected function getYearBySecond(int $seconds)
+    {
+        $result = '无';
+        if ($seconds >= 86400 * 365) {
+            $year = floor($seconds / (86400 * 365));
+            $result = $year . '年';
+        }
+        return $result;
+    }
+}

